#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *A = malloc(sizeof(long long)*N);
        for(int i=0;i<N;i++) scanf("%lld", &A[i]);
        int left=0, right=N-1;
        long long left_max=A[0], right_max=A[N-1];
        long long water=0;
        while(left<right){
            if(left_max<right_max){
                left++;
                if(A[left]>left_max) left_max=A[left];
                else water+=left_max-A[left];
            }else{
                right--;
                if(A[right]>right_max) right_max=A[right];
                else water+=right_max-A[right];
            }
        }
        printf("%lld\n", water);
        free(A);
    }
    return 0;
}

