import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        left, right = 0, N - 1
        left_max = A[0]
        right_max = A[-1]
        water = 0
        while left < right:
            if left_max < right_max:
                left += 1
                if A[left] > left_max:
                    left_max = A[left]
                else:
                    water += left_max - A[left]
            else:
                right -= 1
                if A[right] > right_max:
                    right_max = A[right]
                else:
                    water += right_max - A[right]
        out.append(str(water))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

